sql:
SELECT conservation_date, conservation_description
FROM conservation_records
WHERE conservation_description LIKE '%techniques%';

SELECT COUNT(artwork_id) AS loaned_artworks_count
FROM loan_records
WHERE loan_location = 'National Gallery';

SELECT MAX(conservation_date) AS most_recent_conservation_date
FROM conservation_records
WHERE artwork_id = 1036;

external_knowledge:
- "restored" refers to conservation activities that involve repairing or improving the condition of an artwork;
- "new decade" refers to the period starting from January 1, 2010;
- "12 months" is approximately equivalent to one year.

sql:
SELECT artwork_id, MAX(conservation_date) AS latest_conservation_date
FROM conservation_records
GROUP BY artwork_id;
